.darma-loader-cssloaders-github-08 {
  display: inline-block;
  width: 116px;
  height: 12px;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #6366f1) 16%, transparent);
  overflow: hidden;
}
.darma-loader-cssloaders-github-08::before {
      content: "";
      display: block;
      width: 42%;
      height: 100%;
      border-radius: inherit;
      background: linear-gradient(90deg, var(--loader-color, #6366f1), var(--loader-secondary-color, #a5b4fc));
      animation: darma-loader-cssloaders-github-08-progressSlide 0.9s ease-in-out infinite;
    }
    @keyframes darma-loader-cssloaders-github-08-progressSlide { 0% { transform: translateX(-120%); } 100% { transform: translateX(260%); } }

